webviewllm.preprocess:
// 自动清理网页冗余内容
document.querySelectorAll('header, footer, .ad, .nav, .sidebar').forEach(el => el.remove());
// 提取正文区域（可根据网页结构调整选择器）
const content = document.querySelector('main, .content, .post-content, article').innerHTML;
return content;

